// Generated by Cursor
const fs = require('fs');
const path = require('path');
const moment = require('moment');

const MATCH_LEVELS_DATA_FILE = path.join('app/data', 'higher-levels-matching.xml');

function readMatchLevelsDays() {
  try {
    const xml = fs.readFileSync(MATCH_LEVELS_DATA_FILE, 'utf8');
    const days = [];
    const dayPattern = /<day date="([^"]+)">([\s\S]*?)<\/day>/g;
    const levelPattern = /<level number="([123])">\s*<matches>(\d+)<\/matches>\s*<noMatches>(\d+)<\/noMatches>\s*<\/level>/g;
    let dayMatch;

    while ((dayMatch = dayPattern.exec(xml)) !== null) {
      const levels = {
        1: { matches: 0, noMatches: 0 },
        2: { matches: 0, noMatches: 0 },
        3: { matches: 0, noMatches: 0 }
      };
      let levelMatch;

      while ((levelMatch = levelPattern.exec(dayMatch[2])) !== null) {
        levels[levelMatch[1]] = {
          matches: parseInt(levelMatch[2], 10),
          noMatches: parseInt(levelMatch[3], 10)
        };
      }

      days.push({ date: dayMatch[1], levels });
    }

    return days;
  } catch (error) {
    console.error('[higher-levels-matching] Failed to read XML:', error.message);
    return [];
  }
}

function formatMatchLevelPct(part, total) {
  if (!total) return '0.00%';
  return `${((part / total) * 100).toFixed(2)}%`;
}

function aggregateMatchLevelRaw(days, levelNumber) {
  let matches = 0;
  let noMatches = 0;

  days.forEach((day) => {
    const level = day.levels[levelNumber];
    matches += level.matches;
    noMatches += level.noMatches;
  });

  const total = matches + noMatches;

  return {
    matches,
    noMatches,
    total,
    matchesPct: formatMatchLevelPct(matches, total),
    noMatchesPct: formatMatchLevelPct(noMatches, total)
  };
}

function aggregateMatchLevel(days, levelNumber) {
  const raw = aggregateMatchLevelRaw(days, levelNumber);

  return {
    matches: raw.matches.toLocaleString('en-GB'),
    noMatches: raw.noMatches.toLocaleString('en-GB'),
    total: raw.total.toLocaleString('en-GB'),
    matchesPct: raw.matchesPct,
    noMatchesPct: raw.noMatchesPct
  };
}

const EU_ROW_SPLIT_RATIOS = {
  1: {
    matches: [1350, 579],
    noMatches: [21, 9]
  },
  2: {
    matches: [1247, 535],
    noMatches: [124, 53]
  },
  3: {
    matches: [888, 380],
    noMatches: [484, 207]
  }
};

function splitEuRow(total, euSample, rowSample) {
  const splitTotal = euSample + rowSample;

  if (!splitTotal || !total) {
    return { eu: 0, row: 0 };
  }

  const eu = Math.round((total * euSample) / splitTotal);

  return {
    eu,
    row: total - eu
  };
}

function aggregateMatchLevelEuRowRaw(days, levelNumber) {
  const ratios = EU_ROW_SPLIT_RATIOS[levelNumber];
  let euMatches = 0;
  let rowMatches = 0;
  let euNoMatches = 0;
  let rowNoMatches = 0;

  days.forEach((day) => {
    const level = day.levels[levelNumber];
    const matches = splitEuRow(level.matches, ratios.matches[0], ratios.matches[1]);
    const noMatches = splitEuRow(level.noMatches, ratios.noMatches[0], ratios.noMatches[1]);

    euMatches += matches.eu;
    rowMatches += matches.row;
    euNoMatches += noMatches.eu;
    rowNoMatches += noMatches.row;
  });

  const totalMatches = euMatches + rowMatches;
  const totalNoMatches = euNoMatches + rowNoMatches;
  const grandTotal = totalMatches + totalNoMatches;

  return {
    euMatches,
    rowMatches,
    totalMatches,
    euNoMatches,
    rowNoMatches,
    totalNoMatches,
    grandTotal
  };
}

function formatMatchLevelEuRow(raw) {
  const formatCount = (value) => value.toLocaleString('en-GB');
  const grandTotal = raw.grandTotal;

  return {
    euMatches: formatCount(raw.euMatches),
    euMatchesPct: formatMatchLevelPct(raw.euMatches, grandTotal),
    rowMatches: formatCount(raw.rowMatches),
    rowMatchesPct: formatMatchLevelPct(raw.rowMatches, grandTotal),
    totalMatches: formatCount(raw.totalMatches),
    totalMatchesPct: formatMatchLevelPct(raw.totalMatches, grandTotal),
    euNoMatches: formatCount(raw.euNoMatches),
    euNoMatchesPct: formatMatchLevelPct(raw.euNoMatches, grandTotal),
    rowNoMatches: formatCount(raw.rowNoMatches),
    rowNoMatchesPct: formatMatchLevelPct(raw.rowNoMatches, grandTotal),
    totalNoMatches: formatCount(raw.totalNoMatches),
    totalNoMatchesPct: formatMatchLevelPct(raw.totalNoMatches, grandTotal)
  };
}

function getMatchLevelsDaysForRange(startDate, endDate) {
  const start = moment(startDate, 'DD/MM/YYYY', true).startOf('day');
  const end = moment(endDate, 'DD/MM/YYYY', true).endOf('day');

  if (!start.isValid() || !end.isValid() || start.isAfter(end)) {
    return [];
  }

  return readMatchLevelsDays().filter((day) => {
    const dayMoment = moment(day.date, 'YYYY-MM-DD', true);
    return dayMoment.isValid() && dayMoment.isBetween(start, end, undefined, '[]');
  });
}

function getMatchLevelsStatsForRange(startDate, endDate) {
  const days = getMatchLevelsDaysForRange(startDate, endDate);

  if (!days.length) {
    return null;
  }

  return {
    level1: aggregateMatchLevel(days, 1),
    level2: aggregateMatchLevel(days, 2),
    level3: aggregateMatchLevel(days, 3)
  };
}

function getMatchLevelsEuRowStatsForRange(startDate, endDate) {
  const days = getMatchLevelsDaysForRange(startDate, endDate);

  if (!days.length) {
    return null;
  }

  return {
    level1: formatMatchLevelEuRow(aggregateMatchLevelEuRowRaw(days, 1)),
    level2: formatMatchLevelEuRow(aggregateMatchLevelEuRowRaw(days, 2)),
    level3: formatMatchLevelEuRow(aggregateMatchLevelEuRowRaw(days, 3))
  };
}

function formatUkDateLabel(ddmmyyyy) {
  const [dd, mm, yyyy] = String(ddmmyyyy).split('/');
  if (!dd || !mm || !yyyy) return ddmmyyyy;

  const months = [
    'January', 'February', 'March', 'April', 'May', 'June',
    'July', 'August', 'September', 'October', 'November', 'December'
  ];
  const month = months[parseInt(mm, 10) - 1];

  return `${parseInt(dd, 10)} ${month} ${yyyy}`;
}

function formatMatchLevelsDateRange(startDate, endDate) {
  if (!startDate || !endDate) return '';

  return `${formatUkDateLabel(startDate)} at 00:00 to ${formatUkDateLabel(endDate)} at 23:59`;
}

const q = (value) => `"${String(value ?? '').replace(/"/g, '""')}"`;
const joinCSV = (values) => values.join(',');
const withBOM = (value) => `\uFEFF${value}`;

function buildMatchLevelsSummaryCsv(startDate, endDate) {
  const days = getMatchLevelsDaysForRange(startDate, endDate);

  if (!days.length) {
    return null;
  }

  const meta = [
    joinCSV([q('BTMS — Higher levels of matching')]),
    joinCSV([q(`Date range: ${formatMatchLevelsDateRange(startDate, endDate)}`)]),
    ''
  ].join('\n');

  const header = joinCSV(['Level', 'Category', 'Count', 'Percentage']);
  const summaryRows = [1, 2, 3].flatMap((levelNumber) => {
    const level = aggregateMatchLevelRaw(days, levelNumber);

    return [
      joinCSV([q(levelNumber), q('Matches'), q(level.matches), q(level.matchesPct)]),
      joinCSV([q(levelNumber), q('No matches'), q(level.noMatches), q(level.noMatchesPct)]),
      joinCSV([q(levelNumber), q('Total'), q(level.total), q('')])
    ];
  });

  return [meta, header, summaryRows.join('\n'), ''].join('\n');
}

function buildMatchLevelsEuRowCsv(startDate, endDate) {
  const days = getMatchLevelsDaysForRange(startDate, endDate);

  if (!days.length) {
    return null;
  }

  const meta = [
    joinCSV([q('BTMS — EU and RoW split')]),
    joinCSV([q(`Date range: ${formatMatchLevelsDateRange(startDate, endDate)}`)]),
    ''
  ].join('\n');

  const header = joinCSV(['Level', 'Category', 'Count', 'Percentage']);
  const euRowRows = [1, 2, 3].flatMap((levelNumber) => {
    const level = aggregateMatchLevelEuRowRaw(days, levelNumber);
    const grandTotal = level.grandTotal;
    const pct = (value) => formatMatchLevelPct(value, grandTotal);

    return [
      joinCSV([q(levelNumber), q('EU matches'), q(level.euMatches), q(pct(level.euMatches))]),
      joinCSV([q(levelNumber), q('RoW matches'), q(level.rowMatches), q(pct(level.rowMatches))]),
      joinCSV([q(levelNumber), q('Total matches'), q(level.totalMatches), q(pct(level.totalMatches))]),
      joinCSV([q(levelNumber), q('EU no matches'), q(level.euNoMatches), q(pct(level.euNoMatches))]),
      joinCSV([q(levelNumber), q('RoW no matches'), q(level.rowNoMatches), q(pct(level.rowNoMatches))]),
      joinCSV([q(levelNumber), q('Total no matches'), q(level.totalNoMatches), q(pct(level.totalNoMatches))])
    ];
  });

  return [meta, header, euRowRows.join('\n'), ''].join('\n');
}

function attachMatchLevelsToSessionData(sessionData) {
  if (!sessionData) return;

  const startDate = (sessionData.startDate || '').trim();
  const endDate = (sessionData.endDate || '').trim();

  if (!startDate || !endDate) {
    sessionData.matchLevelsSearchResults = false;
    sessionData.matchLevelsStats = null;
    sessionData.matchLevelsEuRowStats = null;
    sessionData.matchLevelsDisplayDateRange = '';
    return;
  }

  const matchLevelsStats = getMatchLevelsStatsForRange(startDate, endDate);
  const matchLevelsEuRowStats = getMatchLevelsEuRowStatsForRange(startDate, endDate);

  sessionData.matchLevelsDisplayDateRange = formatMatchLevelsDateRange(startDate, endDate);
  sessionData.matchLevelsSearchResults = !!matchLevelsStats;
  sessionData.matchLevelsStats = matchLevelsStats;
  sessionData.matchLevelsEuRowStats = matchLevelsEuRowStats;
}

module.exports = {
  attachMatchLevelsToSessionData,
  buildMatchLevelsSummaryCsv,
  buildMatchLevelsEuRowCsv,
  formatMatchLevelsDateRange,
  getMatchLevelsStatsForRange,
  withBOM
};
